const results = [];

// Auto-balance missing closing braces/brackets
function balanceJson(str) {
  let opens = 0, arrOpens = 0;
  let inString = false, escaped = false;

  for (const ch of str) {
    if (escaped)          { escaped = false; continue; }
    if (ch === '\\')      { escaped = true; continue; }
    if (ch === '"')       { inString = !inString; continue; }
    if (inString)         continue;
    if (ch === '{')       opens++;
    else if (ch === '}')  opens--;
    else if (ch === '[')  arrOpens++;
    else if (ch === ']')  arrOpens--;
  }

  // Append whatever is missing
  return str
    + ']'.repeat(Math.max(0, arrOpens))
    + '}'.repeat(Math.max(0, opens));
}

for (const item of $input.all()) {
  let raw = item.json.content || item.json.message?.content || "";

  let text = raw
    .replace(/```json\s*/gi, "")
    .replace(/```/g, "")
    .trim();

  const match = text.match(/\{[\s\S]*/);
  if (!match) {
    results.push({ json: { _parseError: "No JSON found", _raw: raw } });
    continue;
  }

  let jsonStr = match[0];

  // Fix unquoted string values
  jsonStr = jsonStr.replace(
    /:\s*([A-Za-z][A-Za-z0-9_\-]*)\s*([,\}\n])/g,
    (m, val, end) => {
      if (['true', 'false', 'null'].includes(val)) return `: ${val}${end}`;
      return `: "${val}"${end}`;
    }
  );

  // Auto-close missing braces/brackets
  jsonStr = balanceJson(jsonStr);

  let parsed;
  try {
    parsed = JSON.parse(jsonStr);
  } catch (e) {
    results.push({ json: { _parseError: e.message, _raw: raw, _cleaned: jsonStr } });
    continue;
  }

  const mapped = {
    commentId:       parsed.id || parsed.commentId || null,
    videoId:         parsed.videoId || null,
    sentiment_label: parsed.sentiment_label || "neutral",
    topics:          parsed.topics || null,
    is_complaint:    parsed.is_complaint ? 1 : 0,
    is_request:      parsed.is_request   ? 1 : 0,
    category:        parsed.category     || null,
    subtopic:        parsed.subtopic     || null,
    keywords:        Array.isArray(parsed.keywords)
                       ? JSON.stringify(parsed.keywords)
                       : parsed.keywords || null,
    created_at:      new Date().toISOString().replace("T", " ").substring(0, 19),
  };

  results.push({ json: mapped });
}

return results;

return $('PARSE AI OUTPUT').all().map(item => ({
